27	export async function processMatches(game, { animateMerges, animateUnblocking } = {}) {
28	    const matchGroups = game.findMatches();
29	
30	    // Capture user swap flag before resetting (needed for processMerges callback)
31	    const wasUserSwap = game.isUserSwap;
32	    game.isUserSwap = false;
33	
34	    if (matchGroups.length === 0) {
35	        // No matches found, allow interactions again
36	        game.animating = false;
37	        game.updateGoalDisplay(true);
38	        return;
39	    }
40	
41	    // Calculate score using display values (not internal values)
42	    let totalScore = 0;
43	    matchGroups.forEach((group) => {
44	        const displayValue = getDisplayValue(group.value);
45	        totalScore += displayValue * group.tiles.length;
46	    });
47	
48	    // Update score
49	    game.score += totalScore;
50	    game.saveScore(); // Save score to localStorage
51	
52	    // Track score towards score goals
53	    game.levelGoals.forEach((goal) => {
54	        if (goal.goalType === "score") {
55	            goal.current += totalScore;
56	        }
57	    });
58	
59	    // Check for pending formation tutorials (only on user swaps)
60	    let showedTutorial = false;
61	    if (wasUserSwap) {
62	        const pendingTutorials = getPendingFormationTutorials(matchGroups, game.lastSwapPosition);
63	
64	        if (pendingTutorials.length > 0) {
65	            showedTutorial = true;
66	
67	            // Highlight all tiles that will be merged and blocked tiles that will be removed
68	            highlightMergeTiles(matchGroups);
69	            highlightBlockedTiles(game, matchGroups);
70	
71	            // Wait 500ms so user can see the highlighted tiles before dialog opens
72	            await new Promise((resolve) => setTimeout(resolve, 500));
73	
74	            // Determine swap direction the same way merge-processor does for freeswap tiles
75	            const swapPos = game.lastSwapPosition;
76	            const isHorizontalSwap = swapPos && swapPos.movedFrom ? swapPos.movedFrom.row === swapPos.row : false;
77	
78	            // Show each tutorial dialog and wait for user to close it
79	            for (const { formationType, matchGroup } of pendingTutorials) {
80	                await showFormationTutorialDialog(formationType, matchGroup, isHorizontalSwap);
81	            }
82	
83	            // Wait 800ms after dialog closes before continuing
84	            await new Promise((resolve) => setTimeout(resolve, 800));
85	
86	            // Clear the highlight
87	            clearMergeHighlight();
88	        }
89	    }
90	
91	    // Slow down animations after tutorial so user can see what happens
92	    const speedMultiplier = showedTutorial ? 2 : 1;
93	
94	    // Check for blocked tiles adjacent to original match positions and unblock them
95	    // Done after tutorial dialogs so blocked tiles are still visible during tutorial
96	    const blockedTilesToRemove = unblockAdjacentTiles(game, matchGroups);
97	
98	    // Animate blocked tile removal
99	    if (animateUnblocking) {
100	        animateUnblocking(
101	            game,
102	            blockedTilesToRemove,
103	            () => game.updateBlockedTileGoals(),
104	            (check) => game.updateGoalDisplay(check),
105	            speedMultiplier,
106	        );
107	    }
108	
109	    // Start merge animations, or process merges directly if no animation callback
110	    if (animateMerges) {
111	        animateMerges(
112	            game,
113	            matchGroups,
114	            (matchGroups) => processMerges(game, matchGroups, wasUserSwap),
115	            speedMultiplier,
116	        );
117	    } else {
118	        processMerges(game, matchGroups, wasUserSwap);
119	    }
120	}
