122	export function processMerges(game, matchGroups, wasUserSwap = false) {
123	    // Check for sticky free swap tiles BEFORE clearing the board
124	    matchGroups.forEach((group) => {
125	        group.hasStickyFreeSwap = group.tiles.some((tile) => {
126	            const boardTile = game.board[tile.row][tile.col];
127	            return isTileStickyFreeSwapTile(boardTile);
128	        });
