1	/**
2	 * formation-tutorial.js
3	 *
4	 * Tutorial system for teaching users about different merge formations
5	 * Shows a dialog when user creates a specific formation type for the first time
6	 */
7	
8	import { loadShownFormationTutorials, saveShownFormationTutorial } from "../storage.js";
9	import {
10	    isBlocked,
11	    isBlockedWithLife,
12	    isBlockedMovable,
13	    isBlockedWithMergeCount,
14	    getDisplayValue,
15	} from "../tile-helpers.js";
16	
17	/**
18	 * Get pending formation tutorials for match groups
19	 * @param {Array} matchGroups - Array of match groups from findMatches()
20	 * @param {object|null} swapPosition - Last swap position {row, col, movedFrom: {row, col}}
21	 * @returns {Array<{formationType: string, matchGroup: object}>} Array of pending tutorials with their match groups
22	 */
23	export function getPendingFormationTutorials(matchGroups, swapPosition = null) {
24	    const pending = [];
25	    const seenTypes = new Set();
26	    const shownTutorials = loadShownFormationTutorials();
27	
28	    // Filter to only active merges (containing swapped tiles) if swapPosition provided
29	    const filteredGroups = swapPosition
30	        ? matchGroups.filter((group) => {
31	              return group.tiles.some(
32	                  (tile) =>
33	                      (tile.row === swapPosition.row && tile.col === swapPosition.col) ||
34	                      (swapPosition.movedFrom &&
35	                          tile.row === swapPosition.movedFrom.row &&
36	                          tile.col === swapPosition.movedFrom.col),
37	              );
38	          })
39	        : matchGroups;
40	
41	    filteredGroups.forEach((group) => {
42	        const formationType = getFormationTypeFromDirection(group.direction);
43	        if (formationType && !seenTypes.has(formationType) && !shownTutorials.has(formationType)) {
44	            seenTypes.add(formationType);
45	            pending.push({ formationType, matchGroup: group });
46	        }
47	    });
48	
49	    return pending;
50	}
51	
52	/**
53	 * Highlight tiles that will be merged using merge-preview class
54	 * @param {Array} matchGroups - Array of match groups to highlight
55	 */
56	export function highlightMergeTiles(matchGroups) {
57	    matchGroups.forEach((group) => {
58	        group.tiles.forEach((tile) => {
59	            const gem = document.querySelector(`[data-row="${tile.row}"][data-col="${tile.col}"]`);
60	            if (gem) {
61	                gem.classList.add("merge-preview");
62	            }
63	        });
64	    });
65	}
66	
67	/**
68	 * Highlight blocked tiles adjacent to match tiles using unblock-preview class
69	 * @param {Match3Game} game - The game instance
70	 * @param {Array} matchGroups - Array of match groups
71	 */
72	export function highlightBlockedTiles(game, matchGroups) {
73	    const highlighted = new Set();
74	
75	    matchGroups.forEach((group) => {
76	        group.tiles.forEach((tile) => {
77	            const adjacentPositions = [
78	                { row: tile.row - 1, col: tile.col },
79	                { row: tile.row + 1, col: tile.col },
80	                { row: tile.row, col: tile.col - 1 },
81	                { row: tile.row, col: tile.col + 1 },
82	            ];
83	
84	            adjacentPositions.forEach((pos) => {
85	                if (pos.row >= 0 && pos.row < game.boardHeight && pos.col >= 0 && pos.col < game.boardWidth) {
86	                    const key = `${pos.row}_${pos.col}`;
87	                    if (highlighted.has(key)) return;
88	
89	                    const adjacentTile = game.board[pos.row]?.[pos.col];
90	                    if (
91	                        adjacentTile &&
92	                        (isBlocked(adjacentTile) ||
93	                            isBlockedWithLife(adjacentTile) ||
94	                            isBlockedMovable(adjacentTile) ||
95	                            isBlockedWithMergeCount(adjacentTile))
96	                    ) {
97	                        highlighted.add(key);
98	                        const gem = document.querySelector(`[data-row="${pos.row}"][data-col="${pos.col}"]`);
99	                        if (gem) {
100	                            gem.classList.add("unblock-preview");
101	                        }
102	                    }
103	                }
104	            });
105	        });
106	    });
107	}
108	
109	/**
110	 * Remove merge-preview and unblock-preview highlight from all tiles
111	 */
112	export function clearMergeHighlight() {
113	    document.querySelectorAll(".gem.merge-preview").forEach((gem) => {
114	        gem.classList.remove("merge-preview");
115	    });
116	    document.querySelectorAll(".gem.unblock-preview").forEach((gem) => {
117	        gem.classList.remove("unblock-preview");
118	    });
119	}
